import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def pkg_map(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-2]
        pkgs = {}
        for fw in proj['frameworks']:
            for p in fw['topLevelPackages']:
                pkgs[p['id']] = p['resolvedVersion']
        result[name] = pkgs
    return result

b = pkg_map(baseline)
a = pkg_map(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bv = b.get(proj,{}).get(pkg)
        av = a.get(proj,{}).get(pkg)
        if bv != av:
            print(f'  {proj}/{pkg}: {bv} -> {av}')
            changes = True
if not changes:
    print('  (none - only the two conflicting packages changed)')

print()
print('=== UNCHANGED ===')
for proj in sorted(b.keys()):
    for pkg in sorted(b.get(proj,{}).keys()):
        bv = b[proj][pkg]
        av = a.get(proj,{}).get(pkg)
        if bv == av:
            print(f'  {proj}/{pkg}: {av}')
